CREATE OR REPLACE FUNCTION public.check_session_active()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin

    if not exists (
        select 1
        from sessions
        where id = new.session_id
        and status = 'active'
    )
    then
        raise exception 'Session is not active';
    end if;

    return new;

end;
$function$

CREATE OR REPLACE FUNCTION public.get_login_attempts(p_email text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile profiles%rowtype;
begin
  select *
  into v_profile
  from profiles
  where lower(trim(email)) = lower(trim(p_email))
  limit 1;

  return json_build_object(
    'attempts', coalesce(v_profile.login_attempts, 0),
    'lock_until', v_profile.lock_until
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.is_session_active(p_session_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
declare
  v_status text;
  v_last_activity timestamp;
begin

  select status, last_activity
  into v_status, v_last_activity
  from sessions
  where id = p_session_id;

  if v_status is null then
    return false;
  end if;

  if v_status != 'active' then
    return false;
  end if;

  if v_last_activity < now() - interval '5 minutes' then
    return false;
  end if;

  return true;

end;
$function$

CREATE OR REPLACE FUNCTION public.login_full(p_email text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile profiles%rowtype;
  v_attempts int;
  v_max_attempts int := 5;
  v_lock_minutes int := 5;
begin

  -- 🔍 znajdź usera
  select *
  into v_profile
  from profiles
  where lower(trim(email)) = lower(trim(p_email))
  limit 1;

  if v_profile.user_id is null then
    return json_build_object(
      'success', false,
      'code', 'NOT_FOUND',
      'message', 'Użytkownik nie istnieje'
    );
  end if;

  -- 🔒 status
  if v_profile.status <> 'active' then
    return json_build_object(
      'success', false,
      'code', 'INACTIVE',
      'message', 'Konto nieaktywne'
    );
  end if;

  -- 🔒 lock
  if v_profile.lock_until is not null and v_profile.lock_until > now() then
    return json_build_object(
      'success', false,
      'code', 'LOCKED',
      'message', 'Konto zablokowane'
    );
  end if;

  return json_build_object(
    'success', true
  );

end;
$function$

CREATE OR REPLACE FUNCTION public.login_full(p_email text, p_success boolean)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile profiles%rowtype;
  v_attempts int;
  v_max_attempts int := 5;
  v_lock_minutes int := 5;
begin

  -- 🔍 znajdź usera
  select *
  into v_profile
  from profiles
  where lower(trim(email)) = lower(trim(p_email))
  limit 1;

  if v_profile.user_id is null then
    return json_build_object(
      'success', false,
      'code', 'NOT_FOUND',
      'message', 'Użytkownik nie istnieje'
    );
  end if;

  -- 🔒 status
  if v_profile.status <> 'active' then
    return json_build_object(
      'success', false,
      'code', 'INACTIVE',
      'message', 'Konto nieaktywne'
    );
  end if;

  -- 🔒 lock
  if v_profile.lock_until is not null and v_profile.lock_until > now() then
    return json_build_object(
      'success', false,
      'code', 'LOCKED',
      'message', 'Konto zablokowane'
    );
  end if;

  -- ❗ NIEUDANY LOGIN
  if p_success = false then

    update profiles
    set login_attempts = coalesce(login_attempts, 0) + 1
    where user_id = v_profile.user_id
    returning login_attempts into v_attempts;

    if v_attempts >= v_max_attempts then
      update profiles
      set lock_until = now() + interval '5 minutes'
      where user_id = v_profile.user_id;

      return json_build_object(
        'success', false,
        'code', 'LOCKED',
        'message', 'Konto zablokowane',
        'attempts', v_attempts,
        'remaining', 0
      );
    else
      return json_build_object(
        'success', false,
        'code', 'INVALID_PASSWORD',
        'message', 'Nieprawidłowe dane',
        'attempts', v_attempts,
        'remaining', v_max_attempts - v_attempts
      );
    end if;

  end if;

  -- ✅ SUKCES → tylko informacja (bez resetu!)
  return json_build_object(
    'success', true,
    'code', 'OK'
  );

end;
$function$

CREATE OR REPLACE FUNCTION public.login_precheck(p_email text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile profiles%rowtype;
begin
  select *
  into v_profile
  from profiles
  where lower(trim(email)) = lower(trim(p_email))
  limit 1;

  if v_profile.user_id is null then
    return json_build_object(
      'success', false,
      'message', 'Użytkownik nie istnieje'
    );
  end if;

  if v_profile.status <> 'active' then
    return json_build_object(
      'success', false,
      'message', 'Konto nieaktywne'
    );
  end if;

  if v_profile.lock_until is not null and v_profile.lock_until > now() then
    return json_build_object(
      'success', false,
      'message', 'Konto zablokowane'
    );
  end if;

  return json_build_object(
    'success', true
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.update_inventory_history_entry(p_entry_id uuid, p_reason_code text, p_comment text DEFAULT NULL::text, p_changes jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_role text;
  v_old public.entries%rowtype;
  v_new public.entries%rowtype;
  v_location_exists boolean;
  v_product record;
  v_normalized_type text;
  v_quantity numeric;
  v_expiry_text text;
  v_is_privileged boolean;
begin
  select lower(coalesce(p.role, ''))
  into v_role
  from public.profiles p
  where p.user_id = auth.uid()
  limit 1;

  v_is_privileged := v_role in ('admin', 'primeuser', 'superuser');

  if v_role is null then
    raise exception 'Brak uprawnien do edycji historii operacji';
  end if;

  if p_reason_code is null or btrim(p_reason_code) = '' then
    raise exception 'Powod korekty jest wymagany';
  end if;

  select *
  into v_old
  from public.entries e
  where e.id = p_entry_id
  limit 1;

  if v_old.id is null then
    raise exception 'Wpis nie istnieje';
  end if;

  if not v_is_privileged then
    if lower(coalesce(v_old.approval_status, 'pending')) = 'approved' then
      raise exception 'Operacja zatwierdzona nie moze byc edytowana przez operatora';
    end if;

    if v_old.user_id is distinct from auth.uid() then
      raise exception 'Mozesz edytowac tylko wlasne niezatwierdzone operacje';
    end if;
  end if;

  if p_changes ? 'location' and nullif(p_changes->>'location', '') is not null then
    select exists (
      select 1
      from public.locations l
      where l.code = p_changes->>'location'
    )
    into v_location_exists;

    if not v_location_exists then
      raise exception 'Niepoprawna lokalizacja';
    end if;
  end if;

  if p_changes ? 'sku' and nullif(p_changes->>'sku', '') is not null then
    select id, sku, ean
    into v_product
    from public.products p
    where p.sku = p_changes->>'sku'
    limit 1;

    if v_product.id is null then
      raise exception 'Niepoprawny SKU';
    end if;
  elsif v_old.sku is not null then
    select id, sku, ean
    into v_product
    from public.products p
    where p.sku = v_old.sku
    limit 1;
  end if;

  v_normalized_type := lower(coalesce(nullif(p_changes->>'type', ''), v_old.type, ''));
  if v_normalized_type in ('shortage', 'brak') then
    v_normalized_type := 'brak';
  elsif v_normalized_type in ('surplus', 'nadwyzka', 'nadwyżka') then
    v_normalized_type := 'surplus';
  elsif v_normalized_type = 'checked_empty' then
    v_normalized_type := 'checked_empty';
  elsif v_normalized_type = 'problem' then
    v_normalized_type := 'problem';
  end if;

  if p_changes ? 'quantity' and nullif(p_changes->>'quantity', '') is not null then
    v_quantity := (p_changes->>'quantity')::numeric;
  else
    v_quantity := v_old.quantity;
  end if;

  if v_normalized_type <> 'checked_empty' and (v_quantity is null or v_quantity <= 0) then
    raise exception 'Ilosc musi byc wieksza od zera';
  end if;

  v_expiry_text := nullif(coalesce(p_changes->>'expiry', p_changes->>'expiry_date', ''), '');
  if v_expiry_text is not null and v_expiry_text !~ '^\d{4}-\d{2}-\d{2}$' then
    raise exception 'Niepoprawny format daty';
  end if;

  update public.entries e
  set
    location = coalesce(nullif(p_changes->>'location', ''), e.location),
    sku = coalesce(nullif(p_changes->>'sku', ''), e.sku),
    ean = coalesce(nullif(p_changes->>'ean', ''), e.ean, v_product.ean),
    lot = coalesce(nullif(p_changes->>'lot', ''), e.lot),
    expiry = coalesce(nullif(p_changes->>'expiry', '')::date, nullif(p_changes->>'expiry_date', '')::date, e.expiry),
    expiry_date = coalesce(nullif(p_changes->>'expiry_date', '')::date, nullif(p_changes->>'expiry', '')::date, e.expiry_date),
    quantity = case
      when v_normalized_type = 'checked_empty' then coalesce(v_quantity, 0)
      else v_quantity
    end,
    type = coalesce(v_normalized_type, e.type),
    updated_at = now()
  where e.id = p_entry_id
  returning * into v_new;

  insert into public.correction_log (
    entry_id,
    user_id,
    reason,
    comment,
    old_value,
    new_value,
    created_at
  )
  values (
    p_entry_id,
    auth.uid(),
    p_reason_code,
    nullif(btrim(coalesce(p_comment, '')), ''),
    jsonb_build_object(
      'location', v_old.location,
      'sku', v_old.sku,
      'ean', v_old.ean,
      'lot', v_old.lot,
      'expiry', v_old.expiry,
      'expiry_date', v_old.expiry_date,
      'quantity', v_old.quantity,
      'type', v_old.type,
      'approval_status', v_old.approval_status
    ),
    jsonb_build_object(
      'location', v_new.location,
      'sku', v_new.sku,
      'ean', v_new.ean,
      'lot', v_new.lot,
      'expiry', v_new.expiry,
      'expiry_date', v_new.expiry_date,
      'quantity', v_new.quantity,
      'type', v_new.type,
      'approval_status', v_new.approval_status
    ),
    now()
  );

  insert into public.audit_log (
    user_id,
    action,
    payload,
    created_at
  )
  values (
    auth.uid(),
    'UPDATE_ENTRY_CORRECTION',
    jsonb_build_object(
      'entry_id', p_entry_id,
      'reason_code', p_reason_code,
      'comment', nullif(btrim(coalesce(p_comment, '')), ''),
      'before', jsonb_build_object(
        'location', v_old.location,
        'sku', v_old.sku,
        'ean', v_old.ean,
        'lot', v_old.lot,
        'expiry', v_old.expiry,
        'expiry_date', v_old.expiry_date,
        'quantity', v_old.quantity,
        'type', v_old.type
      ),
      'after', jsonb_build_object(
        'location', v_new.location,
        'sku', v_new.sku,
        'ean', v_new.ean,
        'lot', v_new.lot,
        'expiry', v_new.expiry,
        'expiry_date', v_new.expiry_date,
        'quantity', v_new.quantity,
        'type', v_new.type
      )
    ),
    now()
  );

  return p_entry_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_active_session(p_session_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
declare
  v_status text;
  v_last_activity timestamp;
begin
  -- ❗ brak session_id
  if p_session_id is null then
    return false;
  end if;

  select status, last_activity
  into v_status, v_last_activity
  from sessions
  where id = p_session_id;

  -- ❗ brak rekordu
  if v_status is null then
    return false;
  end if;

  -- ❗ status
  if v_status != 'active' then
    return false;
  end if;

  -- ❗ timeout
  if v_last_activity is null then
    return false;
  end if;

  if v_last_activity < now() - interval '5 minutes' then
    return false;
  end if;

  return true;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_session_active()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.sessions
    WHERE id = NEW.session_id
    AND status = 'active'
  ) THEN
    RAISE EXCEPTION 'Session is not active';
  END IF;

  RETURN NEW;
END;
$function$
